code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card } from 'decantr/components';

code.example:
function SpecimenGrid() {
  const { div, span, code } = tags;
  const specimens = [
    { name: 'Primary', value: '--d-primary', style: 'background:var(--d-primary)', preview: null },
    { name: 'Secondary', value: '--d-secondary', style: 'background:var(--d-secondary)', preview: null },
    { name: 'Accent', value: '--d-accent', style: 'background:var(--d-accent)', preview: null },
    { name: 'Muted', value: '--d-muted', style: 'background:var(--d-muted)', preview: null },
    { name: 'Background', value: '--d-bg', style: 'background:var(--d-bg)', preview: null },
    { name: 'Surface', value: '--d-surface-0', style: 'background:var(--d-surface-0)', preview: null }
  ];

  return div({ class: css('_grid _gcaf200 _gap4 _p4') },
    ...specimens.map(s =>
      Card({ class: css('_flex _col') },
        div({ class: css('_flex _center _p6 _bgmuted _r4'), style: s.style },
          s.preview
        ),
        Card.Body({ class: css('_flex _col _gap1') },
          span({ class: css('_textsm _bold') }, s.name),
          code({ class: css('_textxs _fgmuted _fontmono') }, s.value)
        )
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card } from 'decantr/components';

code.example:
function PreviewGrid({ palettes }) {
  const { div, span, code } = tags;

  return div({ class: css('_flex _col _gap4') },
    ...palettes.map(palette =>
      Card({ class: css('_flex _col _gap0') },
        div({ class: css('_flex _r4 _overflow[hidden]') },
          ...palette.colors.map(c =>
            div({ class: css('_flex1 _h20 _trans[flex_0.3s_ease] _h:flex[2]'), style: `background:${c.hex}` },
              div({ class: css('_flex _col _aic _jcc _hfull _opacity0 _h:opacity100 _trans[opacity_0.2s_ease]') },
                span({ class: css('_textsm _bold'), style: `color:${c.contrast}` }, c.hex)
              )
            )
          )
        ),
        Card.Body({ class: css('_flex _aic _jcsb') },
          span({ class: css('_textsm _bold') }, palette.name),
          span({ class: css('_textxs _fgmuted _fontmono') }, `${palette.colors.length} colors`)
        )
      )
    )
  );
}
